// =============================================================================
// EF Core 9 — Cosmos DB Breaking Changes: Required Fixes
// Apply these changes in your Cosmos DB project.
// =============================================================================

using Microsoft.EntityFrameworkCore;

// ---------------------------------------------------------------------------
// FIX 1: Discriminator property renamed from "Discriminator" to "$type"
//
// Existing documents use "Discriminator". Without this fix, EF Core 9 looks
// for "$type" and fails to match existing documents.
// ---------------------------------------------------------------------------
// In your Cosmos DbContext.OnModelCreating:
//
//   modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");
//
// Apply to EVERY entity type stored in existing containers.

// ---------------------------------------------------------------------------
// FIX 2: id property no longer contains discriminator
//
// EF Core 8 stored id as "EntityType|KeyValue" (e.g., "Product|123").
// EF Core 9 stores id as just "123". Existing documents still have the old
// compound format, so FindAsync/point-reads will fail.
// ---------------------------------------------------------------------------
// In your Cosmos DbContext.OnModelCreating:
//
//   modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
//
// Apply to EVERY entity type that has existing documents.

// ---------------------------------------------------------------------------
// FIX 3: Synchronous I/O now throws
//
// The Cosmos DB provider no longer supports sync methods like ToList(),
// First(), SaveChanges(), etc. They throw InvalidOperationException.
// ---------------------------------------------------------------------------
// BEFORE (throws in EF Core 9):
//   var products = db.Products.Where(p => p.Price > 10).ToList();
//   db.SaveChanges();
//
// AFTER (use async equivalents):
//   var products = await db.Products.Where(p => p.Price > 10).ToListAsync();
//   await db.SaveChangesAsync();

// ---------------------------------------------------------------------------
// Example: Complete Cosmos DbContext with all three fixes applied
// ---------------------------------------------------------------------------
class CosmosAppDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...;",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // FIX 1: Preserve old discriminator property name for existing documents
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // FIX 2: Preserve old compound id format for existing documents
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

// ---------------------------------------------------------------------------
// Example: Converting sync queries to async (FIX 3)
// ---------------------------------------------------------------------------
class CosmosQueryExamples
{
    // BEFORE — all of these throw InvalidOperationException in EF Core 9:
    //   db.Products.ToList()
    //   db.Products.First(p => p.Id == id)
    //   db.Products.Count()
    //   db.SaveChanges()

    // AFTER — use async equivalents:
    async System.Threading.Tasks.Task QueryAsync(CosmosAppDbContext db)
    {
        var all = await db.Products.ToListAsync();
        var first = await db.Products.FirstAsync(p => p.Id == 1);
        var count = await db.Products.CountAsync();
        await db.SaveChangesAsync();
    }
}

class Product { public int Id { get; set; } public decimal Price { get; set; } }
class Session { public int Id { get; set; } public string Name { get; set; } = ""; }

